import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useInView } from '../../hooks/useInView';
import './ServicesOverview.css';

const ServicesOverview = () => {
  const [clickedCard, setClickedCard] = useState(null);
  const [clickedProblemCard, setClickedProblemCard] = useState(null);

  const [servicesRef, servicesVisible] = useInView();
  const [agenciesRef, agenciesVisible] = useInView();
  const [featuresRef, featuresVisible] = useInView();

  const handleCardClick = (index) => {
    setClickedCard(index);
    setTimeout(() => setClickedCard(null), 300);
  };

  const handleProblemCardClick = (index) => {
    setClickedProblemCard(index);
    setTimeout(() => setClickedProblemCard(null), 300);
  };

  return (
    <section className="services-overview">
      <div className="container">
        <div
          ref={servicesRef}
          className={`services-grid reveal-group ${servicesVisible ? 'is-visible' : ''}`}
        >
          <div className="service-card reveal-item">
            <div className="service-icon">{'\u{1F4CA}'}</div>
            <h3>Financial Clarity</h3>
            <p>Clear and accurate numbers you can trust</p>
          </div>
          <div className="service-card reveal-item">
            <div className="service-icon">{'\u{1F4B0}'}</div>
            <h3>Profit Protection</h3>
            <p>Keep more of what you earn as you grow</p>
          </div>
          <div className="service-card reveal-item">
            <div className="service-icon">{'\u{1F4C8}'}</div>
            <h3>Structured Growth</h3>
            <p>Finance systems built for scaling agencies</p>
          </div>
        </div>

        <div
          ref={agenciesRef}
          className={`agencies-come-section reveal-group ${agenciesVisible ? 'is-visible' : ''}`}
        >
          <h2 className="section-title reveal-item">Agencies Come to Us When…</h2>
          <div className="problems-grid">
            <div
              className={`problem-card reveal-item ${clickedProblemCard === 0 ? 'clicked' : ''}`}
              onClick={() => handleProblemCardClick(0)}
            >
              <div className="problem-icon">{'\u{274C}'}</div>
              <h4>Their numbers exist but don't guide decisions</h4>
              <p>Bookkeeping is technically done, but not commercially useful.</p>
            </div>
            <div
              className={`problem-card reveal-item ${clickedProblemCard === 1 ? 'clicked' : ''}`}
              onClick={() => handleProblemCardClick(1)}
            >
              <div className="problem-icon">{'\u{1F4C9}'}</div>
              <h4>Profit feels inconsistent</h4>
              <p>Revenue is strong, but margin and cash don't reflect it.</p>
            </div>
            <div
              className={`problem-card reveal-item ${clickedProblemCard === 2 ? 'clicked' : ''}`}
              onClick={() => handleProblemCardClick(2)}
            >
              <div className="problem-icon">{'\u{1F465}'}</div>
              <h4>Hiring feels reactive</h4>
              <p>Headcount decisions are made on optimism rather than visibility.</p>
            </div>
            <div
              className={`problem-card reveal-item ${clickedProblemCard === 3 ? 'clicked' : ''}`}
              onClick={() => handleProblemCardClick(3)}
            >
              <div className="problem-icon">{'\u{23F0}'}</div>
              <h4>Finance feels passive</h4>
              <p>You want proactive guidance, not year end summaries.</p>
            </div>
          </div>
          <div className="cta-center reveal-item">
            <Link to="/contact" className="btn-primary btn-large">
              Book a Free Consultation
            </Link>
          </div>
        </div>

        <div
          ref={featuresRef}
          className={`what-working-section reveal-group ${featuresVisible ? 'is-visible' : ''}`}
        >
          <h2 className="section-title reveal-item">What Working With Greyline Accountants Ltd. Looks Like</h2>
          <div className="features-grid">
            <div
              className={`feature-item reveal-item ${clickedCard === 0 ? 'clicked' : ''}`}
              onClick={() => handleCardClick(0)}
            >
              <div className="feature-icon">{'\u{1F4CB}'}</div>
              <h4>Complete Finance Coverage</h4>
              <p>Bookkeeping, reporting, and advisory aligned under one roof so nothing gets missed.</p>
            </div>
            <div
              className={`feature-item reveal-item ${clickedCard === 1 ? 'clicked' : ''}`}
              onClick={() => handleCardClick(1)}
            >
              <div className="feature-icon">{'\u{1F4B3}'}</div>
              <h4>Transparent Pricing</h4>
              <p>One clear monthly fee. No hourly billing. No surprise invoices.</p>
            </div>
            <div
              className={`feature-item reveal-item ${clickedCard === 2 ? 'clicked' : ''}`}
              onClick={() => handleCardClick(2)}
            >
              <div className="feature-icon">{'\u{1F4AC}'}</div>
              <h4>Direct, Ongoing Access</h4>
              <p>Slack, Zoom, and scheduled reviews so finance conversations happen when they need to.</p>
            </div>
            <div
              className={`feature-item reveal-item ${clickedCard === 3 ? 'clicked' : ''}`}
              onClick={() => handleCardClick(3)}
            >
              <div className="feature-icon">{'\u{1F4CA}'}</div>
              <h4>Clear, Live Reporting</h4>
              <p>Real time numbers that help you make the right decisions.</p>
            </div>
          </div>
          <div className="cta-center reveal-item">
            <Link to="/contact" className="btn-primary btn-large">
              Book a Free Consultation
            </Link>
          </div>
        </div>
      </div>
    </section>
  );
};

export default ServicesOverview;
